// Selecciona el tema rotando en ciclo de 9 basado en hora actual
// Temas: 3 educativos, 3 producto, 3 visión
const temas = [
  {
    id: 'cfdi40',
    categoria: 'educativo',
    titulo: 'CFDI 4.0',
    descripcion: 'Novedades, cambios y obligaciones del CFDI 4.0 para PYMEs mexicanas',
    keywords: ['CFDI 4.0', 'factura electrónica', 'SAT', 'complementos', 'cancelación']
  },
  {
    id: 'resico',
    categoria: 'educativo',
    titulo: 'RESICO',
    descripcion: 'Régimen Simplificado de Confianza: ventajas, requisitos y obligaciones fiscales',
    keywords: ['RESICO', 'régimen simplificado', 'ISR', 'personas físicas', 'facilidades SAT']
  },
  {
    id: 'imss_nomina',
    categoria: 'educativo',
    titulo: 'IMSS y Nómina',
    descripcion: 'Cuotas IMSS, timbrado de nómina, SUA y cumplimiento laboral en México',
    keywords: ['IMSS', 'nómina', 'SUA', 'cuotas patronales', 'timbrado nómina']
  },
  {
    id: 'mve_demo',
    categoria: 'producto',
    titulo: 'Demo Mystic MVE',
    descripcion: 'Demostración de funciones clave de Mystic: facturación, CRM y Brain IA en un flujo real',
    keywords: ['Mystic', 'demo', 'facturación automática', 'CRM PYME', 'Brain IA WhatsApp']
  },
  {
    id: 'caso_exito',
    categoria: 'producto',
    titulo: 'Caso de Éxito Mystic',
    descripcion: 'Historia real de una PYME sonorense que automatizó su contabilidad con Mystic',
    keywords: ['caso de éxito', 'automatización contable', 'PYME Sonora', 'ahorro tiempo', 'Mystic']
  },
  {
    id: 'manual_vs_mystic',
    categoria: 'producto',
    titulo: 'Manual vs Mystic',
    descripcion: 'Comparativa: procesos contables manuales tradicionales versus automatización con Mystic',
    keywords: ['automatización', 'contabilidad manual', 'eficiencia', 'errores humanos', 'Mystic']
  },
  {
    id: 'digitalizacion_sonora',
    categoria: 'vision',
    titulo: 'Digitalización en Sonora',
    descripcion: 'El estado de la transformación digital de las PYMEs en Sonora y el noroeste de México',
    keywords: ['digitalización', 'Sonora', 'PYMEs', 'transformación digital', 'noroeste México']
  },
  {
    id: 'ia_contabilidad',
    categoria: 'vision',
    titulo: 'IA en Contabilidad',
    descripcion: 'Cómo la inteligencia artificial está revolucionando la contabilidad y la fiscalía en México',
    keywords: ['inteligencia artificial', 'contabilidad IA', 'automatización fiscal', 'futuro contable']
  },
  {
    id: 'futuro_fiscal',
    categoria: 'vision',
    titulo: 'El Futuro Fiscal en México',
    descripcion: 'Tendencias fiscales, tecnología SAT y qué esperar en los próximos años para las PYMEs',
    keywords: ['futuro fiscal', 'SAT digital', 'tendencias impuestos', 'facturación 2025', 'PYME México']
  }
];

// Índice rotativo: usa el timestamp de la ejecución para seleccionar el tema
const ahora = new Date();
const horasDesdeEpoch = Math.floor(ahora.getTime() / (1000 * 60 * 60));
const idx = horasDesdeEpoch % temas.length;
const tema = temas[idx];

// Determinar slot horario para personalizar tono
const hora = ahora.getHours();
let slotHorario = 'mañana';
if (hora >= 6 && hora < 12) slotHorario = 'mañana';
else if (hora >= 12 && hora < 18) slotHorario = 'tarde';
else slotHorario = 'noche';

return [{
  json: {
    tema,
    slotHorario,
    horaLocal: ahora.toLocaleString('es-MX', { timeZone: 'America/Hermosillo' }),
    temaIdx: idx
  }
}];

// Construye el prompt para DeepSeek V4 Flash
const { tema, slotHorario, horaLocal } = $input.item.json;

const systemPrompt = `Eres el community manager experto de Mystic, un AI Orchestrator SaaS para PYMEs mexicanas de Sonora Digital Corp.
Tu tono es profesional pero cercano, en español mexicano. Usas emojis con moderación.
Siempre incluyes un CTA claro hacia Mystic.
Conoces perfectamente: CFDI 4.0, SAT, IMSS, nómina, RESICO, y automatización contable.`;

const userPrompt = `Genera contenido de marketing para redes sociales sobre el tema: "${tema.titulo}"

Descripción del tema: ${tema.descripcion}
Palabras clave: ${tema.keywords.join(', ')}
Categoría: ${tema.categoria}
Hora de publicación: ${slotHorario} (${horaLocal})

Genera EXACTAMENTE los siguientes 4 formatos, separados por los marcadores indicados:

---INSTAGRAM---
Caption para Instagram (máximo 150 palabras). Incluye emojis relevantes, hashtags al final (#Mystic #PYMEMéxico #ContabilidadDigital #Sonora y 5 más específicos del tema), y un CTA para visitar el link en bio.

---LINKEDIN---
Post para LinkedIn (máximo 300 palabras). Tono más formal y profesional. Storytelling con dato/estadística, problema, solución con Mystic, y CTA para agendar demo. Sin exceso de emojis.

---TIKTOK---
Guión para TikTok de 60 segundos. Formato: [0-5s] gancho visual, [5-20s] problema, [20-45s] solución/demo, [45-55s] resultado, [55-60s] CTA. Incluir indicaciones de texto en pantalla entre corchetes.

---TWITTER---
Hilo de Twitter/X con exactamente 5 tweets numerados (1/5, 2/5... 5/5). El tweet 1 debe ser el gancho con estadística o pregunta provocadora. El tweet 5 debe ser el CTA con link placeholder. Máximo 280 caracteres por tweet.`;

return [{
  json: {
    tema,
    slotHorario,
    horaLocal,
    anthropicPayload: {
      model: 'deepseek-v4-flash-free',
      max_tokens: 2048,
      system: systemPrompt,
      messages: [
        { role: 'user', content: userPrompt }
      ]
    }
  }
}];

// Extrae y parsea las 4 variantes de contenido del response de Anthropic
const anthropicResponse = $input.item.json;
const temaData = $('Construir Prompt Anthropic').first().json;

// Extraer texto generado
const contenidoRaw = anthropicResponse?.content?.[0]?.text || '';

if (!contenidoRaw) {
  throw new Error('Anthropic no retornó contenido. Response: ' + JSON.stringify(anthropicResponse).slice(0, 300));
}

// Parsear secciones por marcadores
function extraerSeccion(texto, marcador) {
  const regex = new RegExp(`---${marcador}---([\\s\\S]*?)(?=---[A-Z]+---|$)`, 'i');
  const match = texto.match(regex);
  return match ? match[1].trim() : `[Contenido ${marcador} no generado]`;
}

const instagram = extraerSeccion(contenidoRaw, 'INSTAGRAM');
const linkedin = extraerSeccion(contenidoRaw, 'LINKEDIN');
const tiktok = extraerSeccion(contenidoRaw, 'TIKTOK');
const twitter = extraerSeccion(contenidoRaw, 'TWITTER');

// Construir mensaje resumen para Telegram
const tema = temaData.tema;
const horaLocal = temaData.horaLocal;

const mensajeTelegram = `🚀 *Mystic Content Factory*\n` +
  `📅 ${horaLocal}\n` +
  `🏷️ Tema: *${tema.titulo}* (${tema.categoria})\n` +
  `📊 Índice #${$('Seleccionar Tema Rotativo').first().json.temaIdx + 1}/9\n\n` +
  `━━━━━━━━━━━━━━━━━━━━\n` +
  `📸 *INSTAGRAM*\n${instagram.slice(0, 400)}${instagram.length > 400 ? '...' : ''}\n\n` +
  `━━━━━━━━━━━━━━━━━━━━\n` +
  `💼 *LINKEDIN* (preview)\n${linkedin.slice(0, 300)}${linkedin.length > 300 ? '...' : ''}\n\n` +
  `━━━━━━━━━━━━━━━━━━━━\n` +
  `🎵 *TIKTOK* (preview)\n${tiktok.slice(0, 250)}${tiktok.length > 250 ? '...' : ''}\n\n` +
  `━━━━━━━━━━━━━━━━━━━━\n` +
  `🐦 *TWITTER/X*\n${twitter.slice(0, 300)}${twitter.length > 300 ? '...' : ''}\n\n` +
  `✅ Contenido generado con DeepSeek V4 Flash`;

return [{
  json: {
    tema: tema.titulo,
    categoria: tema.categoria,
    horaLocal,
    contenidoCompleto: {
      instagram,
      linkedin,
      tiktok,
      twitter
    },
    mensajeTelegram,
    tokensUsados: anthropicResponse?.usage?.output_tokens || 0
  }
}];

// Log del contenido completo al API interno de Mystic para registro y auditoría
const datos = $input.item.json;
return [{
  json: {
    evento: 'content_factory_generated',
    tema: datos.tema,
    categoria: datos.categoria,
    horaLocal: datos.horaLocal,
    tokensUsados: datos.tokensUsados,
    plataformas: ['instagram', 'linkedin', 'tiktok', 'twitter'],
    timestampUtc: new Date().toISOString()
  }
}];

// Manejo de errores del flujo principal
const err = $input.item.json;
const workflow = 'Mystic Content Factory';
const ahora = new Date().toLocaleString('es-MX', { timeZone: 'America/Hermosillo' });

const errorDetalle = typeof err === 'object'
  ? JSON.stringify(err).slice(0, 400)
  : String(err).slice(0, 400);

const mensajeError = `⚠️ *ERROR — Content Factory*\n\n` +
  `🕐 ${ahora}\n` +
  `🔴 Workflow: ${workflow}\n` +
  `📋 Detalle:\n\`\`\`${errorDetalle}\`\`\`\n\n` +
  `👉 Revisar N8N: /workflows`;

return [{
  json: {
    mensajeError,
    errorDetalle,
    workflow,
    timestampUtc: new Date().toISOString()
  }
}];

// Contenido vacío o inválido — alerta para revisión
const datos = $input.item.json;
const msg = `⚠️ *Content Factory — Contenido Vacío*\n\n` +
  `Tema: ${datos.tema || 'desconocido'}\n` +
  `El modelo no generó contenido parseable.\n` +
  `Tokens usados: ${datos.tokensUsados || 0}\n` +
  `🕐 ${datos.horaLocal}`;
return [{ json: { mensajeError: msg } }];
